  ('social-worker-moex-06110', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於身心障礙社會工作，下列何者敘述錯誤？ 身心障礙類別共八類，包括多重障礙者和重要器官失去功能者 身心障礙分類採用｢國際健康功能與身心障礙分類」（International Classification of Functioning, Disability, and Health） 民國104年通過「身心障礙者權益保障法」部分條文修正 身障福利機構負責人如有性騷擾、性侵害行為、施打毒品、暴力犯罪、行為不檢，經查證屬實者，應 停止職務，不得繼任', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
