  ('social-worker-moex-06112', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '案主自決是社會工作的重要倫理原則，但是案主真的有能力自決嗎？在權力上、知識上、經驗上、資訊 上都相對不足的狀況下，做成的決定也不一定是最佳的抉擇。所以社會工作者在運用案主自決時最好採 取何種原則？ 專家決定的專業主義原則  父權主義的保護原則 尊重科層組織的依法行政原則  在干預計畫過程中讓案主適度貢獻的原則', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
