  ('social-worker-moex-06115', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於臺灣學校社會工作的敘述，下列何者錯誤？ 主要以駐校模式、巡迴模式與方案委託方式進入學校 學校社會工作關心的服務對象包括學生、家庭、學校和社區 工作模式包括學校變遷模式、社會互動模式、社區學校模式 「兒童及少年福利與權益保障法」為學校社會工作進入校園輔導網絡提供了法源依據', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06116', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'essay', '「會談」是社會工作的基本技巧，一般人常把它與日常生活中的談話混淆。請比較
